/**
 * UserLookupAjax: example client-callable script include built on AjaxAdapter.
 *
 * Script Include settings:
 *   Name:            UserLookupAjax
 *   Client callable: true
 *   (Set an ACL / roles as appropriate. Client callable means any UI user can reach it.)
 *
 * Pattern:
 *   - Each endpoint is a pair: a one-line public method (GlideAjax boundary,
 *     generated by AjaxAdapter.expose) and a private `_` method holding the logic.
 *   - Private methods receive already-parsed, correctly typed arguments and return
 *     plain typed values. They never touch getParameter/JSON/stringification, so a
 *     unit test (ATF server test, or any harness) can call them directly:
 *       new UserLookupAjax()._getUserSummary('62826bf03710200044e0bfc8bcbe5df1', { includeGroups: true })
 *   - Three outcomes, three tools (see _getManagerName for all three):
 *       1. Value result: return the data. Absence that is a normal branch is a value
 *          too (return { found: false }), and the client resolves with it.
 *       2. Expected failure the caller must handle: throw AjaxAdapter.fail(msg). The
 *          client rejects with { kind: 'business' } and your message, and nothing is logged.
 *       3. Contract violation / bug: throw a plain Error. The client rejects with
 *          { kind: 'server', reference } and the detail is logged, not leaked.
 *
 * Reuse: extending AbstractAjaxProcessor only ADDS the AJAX plumbing. It does not stop you
 * using this class as ordinary server code. A Business Rule, scheduled job, or another script
 * include can call `new UserLookupAjax()._getUserSummary(id)` directly. The private methods
 * never touch this.request, so constructing without one is fine. Splitting the logic into a
 * separate AJAX-free Service script include is an optional preference (keeping a domain layer
 * off the AJAX base class), not a requirement for reuse.
 */
var UserLookupAjax = Class.create();
UserLookupAjax.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

	/* ------------------------------------------------------------------ *
	 * Public methods: GlideAjax boundary only, one line each.
	 * The client calls: AjaxProxy.call('UserLookupAjax', 'getUserSummary',
	 *   { userId: id, options: { includeGroups: true } }). The named params map
	 *   positionally to the private method's arguments.
	 *
	 * A contract entry ({ name, type?, required?, default? }) is enforced at the
	 * boundary: violations reject with kind 'badRequest' (all listed at once,
	 * nothing logged) and the private method never runs, so it can trust its
	 * arguments. A plain string entry is just the positional mapping.
	 * ------------------------------------------------------------------ */

	getUserSummary: AjaxAdapter.expose('_getUserSummary', [
		{ name: 'userId', type: 'string', required: true },
		{ name: 'options', type: 'object', default: {} },
	]),
	getActiveUserCount: AjaxAdapter.expose('_getActiveUserCount', [
		{ name: 'companyId', type: 'string' },
	]),
	getManagerName: AjaxAdapter.expose('_getManagerName', [
		{ name: 'userId', type: 'string', required: true },
	]),
	getUsersCreatedSince: AjaxAdapter.expose('_getUsersCreatedSince', [
		{ name: 'since', type: 'date', required: true },
	]),

	/* ------------------------------------------------------------------ *
	 * Private methods: typed in, typed out, unit testable.
	 * ------------------------------------------------------------------ */

	/**
	 * Builds a summary of one sys_user record.
	 *
	 * The AJAX boundary contract already guarantees userId is a non-empty-checked string and
	 * options is an object (defaulted to {}), so there are no guard clauses here. Note the
	 * contract only protects the AJAX path: if this method is also called directly by other
	 * server code, that caller is trusted the same way any internal function trusts its caller.
	 *
	 * @param {string} userId - sys_id of the sys_user record.
	 * @param {{ includeGroups?: boolean }} options - Optional flags (boundary default: {}).
	 * @returns {{ found: true, name: string, email: string, groups?: string[] } | { found: false }}
	 */
	_getUserSummary: function(userId, options) {
		var userGr = new GlideRecord('sys_user');
		if (!userGr.get(userId)) {
			// Expected outcome of valid use: model it in the result, don't throw.
			return { found: false };
		}

		var summary = {
			found: true,
			name: String(userGr.getValue('name') || ''),
			email: String(userGr.getValue('email') || ''),
		};
		if (options.includeGroups === true) {
			summary.groups = this._getGroupNames(userId);
		}
		return summary;
	},

	/**
	 * Counts active users, optionally scoped to one company.
	 *
	 * @param {string} [companyId] - sys_id of a core_company record. Omit for all companies.
	 * @returns {number}
	 */
	_getActiveUserCount: function(companyId) {
		var userGa = new GlideAggregate('sys_user');
		userGa.addQuery('active', true);
		if (typeof companyId === 'string' && companyId !== '') {
			userGa.addQuery('company', companyId);
		}
		userGa.addAggregate('COUNT');
		userGa.query();
		// `|| 0` guards a NaN from a non-numeric aggregate. NaN would serialize to null on the wire.
		return userGa.next() ? Number(userGa.getAggregate('COUNT')) || 0 : 0;
	},

	/**
	 * Resolves a user's manager's name and email. Demonstrates all three outcomes.
	 *
	 * @param {string} userId - sys_id of the sys_user record.
	 * @returns {{ name: string, email: string }}
	 * @throws {Error} When userId is missing/not a string (bug, plain throw, kind 'server').
	 * @throws {Error} Via AjaxAdapter.fail for expected failures the caller should surface (kind 'business').
	 */
	_getManagerName: function(userId) {
		if (typeof userId !== 'string' || userId === '') {
			// The boundary contract already enforces this on the AJAX path. The guard is kept
			// deliberately because this method is also called directly by server-side code
			// (Business Rules, jobs), which bypasses the contract. Plain throw, logged, anonymized.
			throw new Error('userId is required and must be a non-empty string');
		}

		var userGr = new GlideRecord('sys_user');
		if (!userGr.get(userId)) {
			// Here absence is a failure the caller must handle (unlike _getUserSummary's
			// { found: false }), so reject with a safe, unlogged business message.
			throw AjaxAdapter.fail('No user matches that sys_id');
		}

		var managerId = String(userGr.getValue('manager') || '');
		if (managerId === '') {
			throw AjaxAdapter.fail('This user has no manager assigned', { details: { userId: userId } });
		}

		var managerGr = new GlideRecord('sys_user');
		if (!managerGr.get(managerId)) {
			throw AjaxAdapter.fail('The assigned manager record no longer exists');
		}
		return {
			name: String(managerGr.getValue('name') || ''),
			email: String(managerGr.getValue('email') || ''),
		};
	},

	/**
	 * Counts users created on or after a moment. Demonstrates date marshalling: the client
	 * passes a JS Date ({ since: new Date(...) }), it arrives here as a real GlideDateTime
	 * (the 'date' contract type guarantees it), and the returned GlideDateTime resolves
	 * client-side as a JS Date.
	 *
	 * @param {GlideDateTime} since - Moment to count from (client sent a Date).
	 * @returns {{ count: number, asOf: GlideDateTime }} asOf arrives client-side as a Date.
	 */
	_getUsersCreatedSince: function(since) {
		var userGa = new GlideAggregate('sys_user');
		userGa.addQuery('sys_created_on', '>=', since);
		userGa.addAggregate('COUNT');
		userGa.query();
		var count = userGa.next() ? Number(userGa.getAggregate('COUNT')) || 0 : 0;
		return { count: count, asOf: new GlideDateTime() };
	},

	/* ------------------------------------------------------------------ *
	 * Helpers.
	 * ------------------------------------------------------------------ */

	/**
	 * Private helper: assumes userId is already validated by its caller, so it carries no guard.
	 *
	 * @param {string} userId - sys_id of the sys_user record.
	 * @returns {string[]} Display names of the groups the user belongs to (empty when none).
	 */
	_getGroupNames: function(userId) {
		var groupNames = [];
		var membershipGr = new GlideRecord('sys_user_grmember');
		membershipGr.addQuery('user', userId);
		membershipGr.query();
		while (membershipGr.next()) {
			groupNames.push(String(membershipGr.group.getDisplayValue()));
		}
		return groupNames;
	},

	type: 'UserLookupAjax',
});
